#include <stdio.h>
#include <math.h>

int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= N; j++) {
                for (int k = 0; k <= N; k++) {
                    double x[N];
                    for (int l = 0; l < N; l++) {
                        if (l == 0) x[l] = (i - N / 2.0) / N;
                        else if (l == 1) x[l] = (j - N / 2.0) / N;
                        else x[l] = (k - N / 2.0) / N;
                    }
                    double norm = sqrt(N);
                    for (int l = 0; l < N; l++) {
                        printf("%.10f ", x[l] / norm);
                    }
                    printf("\n");
                }
            }
        }
        printf("\n");
    }
    return 0;
}

