import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            for (int i = 0; i <= N; i++) {
                for (int j = 0; j <= N; j++) {
                    for (int k = 0; k <= N; k++) {
                        double[] x = new double[N];
                        for (int l = 0; l < N; l++) {
                            if (l == 0) x[l] = (i - N / 2.0) / N;
                            else if (l == 1) x[l] = (j - N / 2.0) / N;
                            else x[l] = (k - N / 2.0) / N;
                        }
                        double norm = Math.sqrt(N);
                        for (int l = 0; l < N; l++) {
                            System.out.print(x[l] / norm + " ");
                        }
                        System.out.println();
                    }
                }
            }
            System.out.println();
        }
    }
}

